 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Button, DescriptionListTerm } from '@patternfly/react-core';
 5	import { PencilAltIcon } from '@patternfly/react-icons';
 6	
 7	import SearchItem from '../SearchItem/SearchItem';
 8	
 9	type HardwareDeviceTitleProps = {
10	  canEdit: boolean;
11	  hideEdit?: boolean;
12	  onClick?: () => void;
13	  title: string;
14	};
15	
16	const HardwareDeviceTitle: FC<HardwareDeviceTitleProps> = ({
17	  canEdit,
18	  hideEdit = false,
19	  onClick,
20	  title,
21	}) => {
22	  const { t } = useKubevirtTranslation();
23	
24	  if (hideEdit) return <DescriptionListTerm>{title}</DescriptionListTerm>;
25	
26	  return (
27	    <DescriptionListTerm>
28	      <Button
29	        className="pf-m-link--align-left"
30	        isDisabled={!canEdit}
31	        isInline
32	        onClick={onClick}
33	        variant="link"
34	      >
35	        <SearchItem id={title.replace(' ', '-')}>
36	          {title}{' '}
37	          <PencilAltIcon alt={t('Edit')} className="co-icon-space-l pf-v6-c-button-icon--plain" />
38	        </SearchItem>
39	      </Button>
40	    </DescriptionListTerm>
41	  );
42	};
43	
44	export default HardwareDeviceTitle;

